import React, { useState } from "react";
import "../styles/search.css";
import icon from './images/logo.png';
// Dummy data for buses (you can replace these with real data or API calls)
const busData = [
  {
    busNumber: "101",
    from: "New York",
    to: "Los Angeles",
    image: {icon}, // Replace with a real image URL
  },
  {
    busNumber: "102",
    from: "New York",
    to: "Chicago",
    image: "https://example.com/bus2.jpg", // Replace with a real image URL
  },
  // Add more bus data as needed
];

const Search = () => {
  // States to store form inputs
  const [from, setFrom] = useState("");
  const [to, setTo] = useState("");
  const [date, setDate] = useState(""); // Keep the date field

  // State to store bus results
  const [busResults, setBusResults] = useState([]);
  
  // State to track search status (whether there are buses or not)
  const [noBuses, setNoBuses] = useState(false);

  // Function to handle form submission and search buses
  const handleSearch = () => {
    if (!from || !to) {
      alert("Please fill all the fields.");
      return;
    }

    // Find buses that match the search criteria (ignoring the date)
    const results = busData.filter(bus => bus.from.toLowerCase() === from.toLowerCase() && bus.to.toLowerCase() === to.toLowerCase());

    if (results.length > 0) {
      setBusResults(results);
      setNoBuses(false);
    } else {
      setNoBuses(true);
      setBusResults([]);
    }

    // Clear the form fields except the date
    setFrom("");
    setTo("");
  };

  return (
    <div className="container">
      <div className="search-container">
        {/* Input Fields */}
        <div className="input-box">
          <input
            type="text"
            placeholder="Enter source"
            value={from}
            onChange={(e) => setFrom(e.target.value)}
          />
        </div>
        <div className="input-box">
          <input
            type="text"
            placeholder="Enter destination"
            value={to}
            onChange={(e) => setTo(e.target.value)}
          />
        </div>

        {/* Date Input (No Verification, still filled in and submitted) */}
        <div className="input-box">
          <input
            type="date"
            value={date}
            onChange={(e) => setDate(e.target.value)}
          />
        </div>

        {/* Search Button */}
        <button onClick={handleSearch} className="search-btn">Search Buses</button>
      </div>

      {/* Display Bus Results */}
      <div className="bus-results">
        {noBuses ? (
          <p>No buses available for this route.</p>
        ) : (
          <ul>
            {busResults.map((bus, index) => (
              <li key={index} className="bus-item">
                <img src={bus.image} alt={`Bus ${bus.busNumber}`} className="bus-image" />
                <h3>Bus Number: {bus.busNumber}</h3>
                <p>From: {bus.from} - To: {bus.to}</p>
                <button className="book-btn">Book Now</button>
              </li>
            ))}
          </ul>
        )}
      </div>
    </div>
  );
};

export default Search;
